# Geometry module using math utilities
from math_utils import PI

class Circle:
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    def area(self) -> float:
        return PI * self.radius * self.radius

    def circumference(self) -> float:
        return 2.0 * PI * self.radius
